def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        if ratio > 1.1:
            priorities[i] = float('inf')
            continue
        score = 0.0
        temp_ratio = ratio
        multiplier = 1.0
        for j in range(7):
            if temp_ratio < 0.005:
                multiplier *= 0.8
                break
            base = np.sqrt(temp_ratio + 0.05) * np.log1p(temp_ratio + 0.1)
            increment = base * (1 / (j + 1)) * multiplier
            score += increment
            if score > 8:
                multiplier *= 0.7
            temp_ratio *= 0.8
            if j % 2 == 1:
                score += (0.05 * (j + 1)) / (1 + ratio)
        if score < 1.0:
            if ratio < 0.3:
                score *= 4
                for k in range(3):
                    penalty = (0.2 / (k + 1)) * (1 - ratio)
                    score += penalty
            else:
                score *= 2.5
        elif score < 4:
            score *= 5
            if capacity < item * 1.1:
                score += 4
        else:
            if ratio > 0.85:
                score *= 15
                for _ in range(2):
                    score += np.log1p(ratio * 10)
            else:
                score *= 9
        if capacity < item * 0.9:
            score += 30
        elif capacity < item * 1.05:
            score += 10
        if score > 50:
            score = 50 + np.log1p(score - 50) * 5
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return np.full_like(priorities, float('inf'))
    min_priority = np.min(finite_priorities)
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_priority * 150
        else:
            if priorities[i] == min_priority:
                priorities[i] = 0
            elif priorities[i] == max_priority:
                priorities[i] *= 1.8
            else:
                priorities[i] = ((priorities[i] - min_priority) / (max_priority - min_priority)) ** 1.2 * 12
    return priorities
